            "qty": 40,
            "price":130,
            "image":"images/img59.png",
            "category":["dinner","breakfast"],
            "sizes":["small","large","medium"]
        },
        {
            "id":5,
            "name":"fries",
            "qty": 20,
            "image":"images/img60.png",
            "price":100,
            "category":["freshfood","lunch"],
            "sizes":["small","large","medium"]
        },
        {
            "id":6,
            "name":"pizza",
            "qty": 20,
            "image":"images/img61.png",
            "price":[70,360,130],
            "category":["freshfood","lunch"],
            "sizes":["small","large","medium"]
        },
        {
            "id":7,
            "name":"chess pasta",
            "qty": 20,
            "image":"images/img62.png",
            "price":170,
            "category":["lunch","breakfast"],
            "sizes":["small","large","medium"]
        },
        {
            "id":8,
            "name":"coffe",
            "qty": 20,
            "image":"images/img63.png",
            "price":70,
            "category":["lunch","breakfast"],
            "sizes":["small","large","medium"]
        }
    ],
    product:{}
}

export const productSlice = createSlice({
    name:"product",
    initialState:initialState,
    reducers:{
      product(state,action){
        const product = state.product.find(product=>product.id === action.id)
      }
    }
});

export  const productActions = productSlice.actions;
export default productSlice
